SELECT a.track_id, a.track_nm, a.album_id, f.artist_id repArtistId, f.artist_nm repArtistNm, a.agency_id, if(a.streaming_premium_yn = 'Y' OR a.pps_yn = 'Y', 'Y', 'N') holdbackYn, a.create_dtime, a.update_dtime, d.artist_id, d.artist_nm, b.album_img_size size, CONCAT(b.album_img_url, '?updateDate=', unix_timestamp(b.update_dtime)) url FROM tb_track a LEFT OUTER JOIN tb_album_img b ON a.album_id = b.album_id LEFT OUTER JOIN ted_trackartist as c ON a.track_id = c.track_id AND c.rp_yn = 'Y' and c.db_sts = 'A' LEFT OUTER JOIN ted_artist d ON c.artist_id = d.artist_id LEFT OUTER JOIN ted_album e ON a.album_id = e.album_id LEFT OUTER JOIN ted_artist f ON a.reprsnt_artist_id = f.artist_id WHERE a.track_id IN
#{trackId}
AND a.disp_status_yn = 'Y'
